	mux.HandleFunc("POST /v1/projects/{project}/plans/{filename}/rename", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		var req struct {
			NewFilename string `json:"new_filename"`
		}
